gene.hits.regions <- 
  group_by(peaks.within.genes, id, PANTHER_accession, nSL_pop) |> 
  slice_max(ABS_nSL, with_ties=FALSE)

gene.hits.regions <- 
  rename(gene.hits.regions, chrom=seqid, pop=nSL_pop) |>
  arrange(chrom, start, pop)
  
gene.hits.regions <- mutate(gene.hits.regions, loc=paste0(chrom, ":", start, "–", end))

gene.hits.regions

write_tsv(x=gene.hits.regions, file="/Volumes/Tigrigobius/tgoby/genes/PANTHER.999/ABS_nSL.gene.hits.regions.tab")

saveRDS(object=gene.hits.regions, file="/Volumes/Tigrigobius/tgoby/genes/PANTHER.999/ABS_nSL.gene.hits.regions.RDS")

# sets
